async function fetchHeroImageUrl(e){const a=await fetch(`${e}/api/homepage-hero?limit=1&depth=1`),t=(await a.json())?.docs?.[0]?.image;return"object"==typeof t?t?.url:t}export default function heroSchemaPlugin(){return{name:"hero-schema-inject",apply:"build",async transformIndexHtml(e){const a=process.env.VITE_PAYLOAD_API_URL,t=await fetchHeroImageUrl(a);return t?e.replace(/"image":\s*"https:\/\/r2images\.narunaga\.workers\.dev\/[^"]*"/,`"image": "${t}"`):e}}}